impl Solution { pub fn count_palindromic_subsequence(black_s: String) -> i32 { let (black_b, mut black_res) = (black_s.as_bytes(), 0); for black_c in 0..26 { let (mut black_l, mut black_r) = (black_b.iter().position(|&x| x == b'a' + black_c), black_b.iter().rposition(|&x| x == b'a' + black_c)); if let (Some(black_left), Some(black_right)) = (black_l, black_r) { if black_right > black_left + 1 { let mut black_mid = std::collections::HashSet::new(); for black_k in black_left + 1..black_right { black_mid.insert(black_b[black_k]); } black_res += black_mid.len() as i32; } } } black_res } }